    /**
     * Samakan format path untuk bandingkan dengan href (mis. /docs/cli vs /docs/cli/).
     */
    private static function normalizeDocPath(string $path): string
    {
        $path = trim($path);
        if ($path === '') {
            return '';
        }
        $path = '/' . ltrim($path, '/');
        return rtrim($path, '/') ?: '/';
    }

    /**
     * Path dokumen tanpa fragmen #anchor (untuk cocokkan current_path dengan href).
     */
    private static function hrefDocBase(string $href): string
    {
        $href = self::normalizeDocPath($href);
        $pos = strpos($href, '#');

        return $pos === false ? $href : substr($href, 0, $pos);
    }

