    /**
     * Get product list data with pagination
     *
     * @param array $params Parameters from route (biasanya berisi current_path dari NexaController)
     * @return array Satu entri dokumen (group, href, title, description) atau [] jika tidak ada kecocokan
     */
    public function list(array $params = []): array
    {
        $items = $this->meta($params);

        $current = self::normalizeDocPath(isset($params['current_path']) ? (string) $params['current_path'] : '');
        if ($current === '') {
            return [];
        }

        $currentBase = self::hrefDocBase($current);

        $items = array_values(array_filter(
            $items,
            static function (array $row) use ($currentBase): bool {
                return self::hrefDocBase((string) ($row['href'] ?? '')) === $currentBase;
            }
        ));

        if ($items === []) {
            return [];
        }

        foreach ($items as $row) {
            if (strpos((string) ($row['href'] ?? ''), '#') === false) {
                return $row;
            }
        }

        return $items[0];
    }
}
